   748→// ResolveAgentForRewind resolves the agent from checkpoint metadata.
   749→// Falls back to the default agent (Claude) for old checkpoints that lack agent info.
   750→func ResolveAgentForRewind(agentType agent.AgentType) (agent.Agent, error) {
   751→	if !isSpecificAgentType(agentType) {
   752→		ag := agent.Default()
   753→		if ag == nil {
   754→			return nil, errors.New("no default agent registered")
   755→		}
   756→		return ag, nil
   757→	}
   758→	ag, err := agent.GetByAgentType(agentType)
   759→	if err != nil {
   760→		return nil, fmt.Errorf("resolving agent %q: %w", agentType, err)
