   765→// ResolveSessionFilePath determines the correct file path for an agent's session transcript.
   766→// Checks session state for transcript_path first (needed for agents like Gemini that store
   767→// transcripts at paths that GetSessionDir can't reconstruct, e.g. SHA-256 hashed directories).
   768→// Falls back to the agent's ExtractAgentSessionID + ResolveSessionFile with fallbackSessionDir.
   769→func ResolveSessionFilePath(sessionID string, ag agent.Agent, fallbackSessionDir string) string {
   770→	state, err := LoadSessionState(sessionID)
   771→	if err == nil && state != nil && state.TranscriptPath != "" {
   772→		return state.TranscriptPath
   773→	}
   774→
