   779→// readSessionPrompt reads the first prompt from the session's prompt.txt file stored in git.
   780→// Returns an empty string if the prompt cannot be read.
   781→func readSessionPrompt(repo *git.Repository, commitHash plumbing.Hash, metadataDir string) string {
