   787→
   788→	tree, err := commit.Tree()
   789→	if err != nil {
   790→		return ""
   791→	}
   792→
   793→	// Look for prompt.txt in the metadata directory
   794→	promptPath := metadataDir + "/" + paths.PromptFileName
   795→	promptEntry, err := tree.File(promptPath)
   796→	if err != nil {
   797→		return ""
   798→	}
   799→
   800→	content, err := promptEntry.Contents()
