   808→// SessionRestoreStatus represents the status of a session being restored.
   809→type SessionRestoreStatus int
   810→
   811→const (
   812→	StatusNew             SessionRestoreStatus = iota // Local file doesn't exist
   813→	StatusUnchanged                                   // Local and checkpoint are the same
   814→	StatusCheckpointNewer                             // Checkpoint has newer entries
   815→	StatusLocalNewer                                  // Local has newer entries (conflict)
   816→)
   817→
   818→// SessionRestoreInfo contains information about a session being restored.
   819→type SessionRestoreInfo struct {
   820→	SessionID      string
   821→	Prompt         string               // First prompt preview for display
   822→	Status         SessionRestoreStatus // Status of this session
   823→	LocalTime      time.Time
   824→	CheckpointTime time.Time
   825→}
