   827→// classifySessionsForRestore checks all sessions in a checkpoint and returns info
   828→// about each session, including whether local logs have newer timestamps.
   829→func (s *ManualCommitStrategy) classifySessionsForRestore(ctx context.Context, sessionDir string, ag agent.Agent, store cpkg.Store, checkpointID id.CheckpointID, summary *cpkg.CheckpointSummary) []SessionRestoreInfo {
   830→	var sessions []SessionRestoreInfo
   831→
   832→	totalSessions := len(summary.Sessions)
   833→	// Check all sessions (0-based indexing)
   834→	for i := range totalSessions {
   835→		content, err := store.ReadSessionContent(ctx, checkpointID, i)
   836→		if err != nil || content == nil || len(content.Transcript) == 0 {
   837→			continue
   838→		}
   839→
   840→		sessionID := content.Metadata.SessionID
   841→		if sessionID == "" {
   842→			continue
   843→		}
   844→
   845→		localPath := ResolveSessionFilePath(sessionID, ag, sessionDir)
   846→
   847→		localTime := paths.GetLastTimestampFromFile(localPath)
   848→		checkpointTime := paths.GetLastTimestampFromBytes(content.Transcript)
   849→		status := ClassifyTimestamps(localTime, checkpointTime)
   850→
   851→		sessions = append(sessions, SessionRestoreInfo{
   852→			SessionID:      sessionID,
   853→			Prompt:         ExtractFirstPrompt(content.Prompts),
   854→			Status:         status,
   855→			LocalTime:      localTime,
   856→			CheckpointTime: checkpointTime,
   857→		})
   858→	}
   859→
   860→	return sessions
   861→}
   862→
   863→// ClassifyTimestamps determines the restore status based on local and checkpoint timestamps.
   864→func ClassifyTimestamps(localTime, checkpointTime time.Time) SessionRestoreStatus {
   865→	// Local file doesn't exist (no timestamp found)
   866→	if localTime.IsZero() {
   867→		return StatusNew
   868→	}
   869→
   870→	// Can't determine checkpoint time - treat as new/safe
   871→	if checkpointTime.IsZero() {
   872→		return StatusNew
   873→	}
   874→
   875→	// Compare timestamps
   876→	if localTime.After(checkpointTime) {
   877→		return StatusLocalNewer
   878→	}
   879→	if checkpointTime.After(localTime) {
   880→		return StatusCheckpointNewer
   881→	}
   882→	return StatusUnchanged
   883→}
   884→
   885→// StatusToText returns a human-readable status string.
   886→func StatusToText(status SessionRestoreStatus) string {
   887→	switch status {
   888→	case StatusNew:
   889→		return "(new)"
   890→	case StatusUnchanged:
   891→		return "(unchanged)"
   892→	case StatusCheckpointNewer:
   893→		return "(checkpoint is newer)"
   894→	case StatusLocalNewer:
   895→		return "(local is newer)" // shouldn't appear in non-conflict list
   896→	default:
   897→		return ""
   898→	}
   899→}
