   901→// PromptOverwriteNewerLogs asks the user for confirmation to overwrite local
   902→// session logs that have newer timestamps than the checkpoint versions.
   903→func PromptOverwriteNewerLogs(sessions []SessionRestoreInfo) (bool, error) {
   904→	// Separate conflicting and non-conflicting sessions
   905→	var conflicting, nonConflicting []SessionRestoreInfo
   906→	for _, s := range sessions {
   907→		if s.Status == StatusLocalNewer {
   908→			conflicting = append(conflicting, s)
   909→		} else {
   910→			nonConflicting = append(nonConflicting, s)
   911→		}
   912→	}
   913→
   914→	fmt.Fprintf(os.Stderr, "\nWarning: Local session log(s) have newer entries than the checkpoint:\n")
   915→	for _, info := range conflicting {
   916→		// Show prompt if available, otherwise fall back to session ID
   917→		if info.Prompt != "" {
   918→			fmt.Fprintf(os.Stderr, "  \"%s\"\n", info.Prompt)
   919→		} else {
   920→			fmt.Fprintf(os.Stderr, "  Session: %s\n", info.SessionID)
   921→		}
   922→		fmt.Fprintf(os.Stderr, "    Local last entry:      %s\n", info.LocalTime.Local().Format("2006-01-02 15:04:05"))
   923→		fmt.Fprintf(os.Stderr, "    Checkpoint last entry: %s\n", info.CheckpointTime.Local().Format("2006-01-02 15:04:05"))
   924→	}
   925→
   926→	// Show non-conflicting sessions with their status
   927→	if len(nonConflicting) > 0 {
   928→		fmt.Fprintf(os.Stderr, "\nThese other session(s) will also be restored:\n")
   929→		for _, info := range nonConflicting {
   930→			statusText := StatusToText(info.Status)
   931→			if info.Prompt != "" {
   932→				fmt.Fprintf(os.Stderr, "  \"%s\" %s\n", info.Prompt, statusText)
   933→			} else {
   934→				fmt.Fprintf(os.Stderr, "  Session: %s %s\n", info.SessionID, statusText)
   935→			}
   936→		}
   937→	}
   938→
   939→	fmt.Fprintf(os.Stderr, "\nOverwriting will lose the newer local entries.\n\n")
   940→
   941→	var confirmed bool
   942→	form := huh.NewForm(
   943→		huh.NewGroup(
   944→			huh.NewConfirm().
   945→				Title("Overwrite local session logs with checkpoint versions?").
   946→				Value(&confirmed),
   947→		),
   948→	)
   949→	if isAccessibleMode() {
   950→		form = form.WithAccessible(true)
   951→	}
   952→
   953→	if err := form.Run(); err != nil {
   954→		if errors.Is(err, huh.ErrUserAborted) {
   955→			return false, nil
   956→		}
   957→		return false, fmt.Errorf("failed to get confirmation: %w", err)
   958→	}
   959→
   960→	return confirmed, nil
   961→}
