   120→	case agent.HookUserPromptSubmit:
   121→		// BeforeAgent is Gemini's equivalent to Claude's UserPromptSubmit
   122→		// It provides the user's prompt in the "prompt" field
   123→		var raw agentHookInputRaw
   124→		if err := json.Unmarshal(data, &raw); err != nil {
   125→			return nil, fmt.Errorf("failed to parse agent hook input: %w", err)
   126→		}
   127→		input.SessionID = raw.SessionID
   128→		input.SessionRef = raw.TranscriptPath
   129→		input.RawData["cwd"] = raw.Cwd
   130→		input.RawData["hook_event_name"] = raw.HookEventName
   131→		if raw.Prompt != "" {
   132→			input.UserPrompt = raw.Prompt
   133→			input.RawData["prompt"] = raw.Prompt
   134→		}
   135→
   136→	case agent.HookPreToolUse, agent.HookPostToolUse:
   137→		var raw toolHookInputRaw
   138→		if err := json.Unmarshal(data, &raw); err != nil {
   139→			return nil, fmt.Errorf("failed to parse tool hook input: %w", err)
   140→		}
