   176→// ResolveSessionFile returns the path to a Gemini session file.
   177→// Gemini names files as session-<date>-<shortid>.json where shortid is the first 8 chars
   178→// of the session UUID. This searches for an existing file matching the pattern, falling
   179→// back to <dir>/<id>.json if no match is found.
   180→func (g *GeminiCLIAgent) ResolveSessionFile(sessionDir, agentSessionID string) string {
   181→	// Try to find existing file matching Gemini's naming convention:
   182→	// session-*-<first8chars>.json
   183→	shortID := agentSessionID
   184→	if len(shortID) > 8 {
   185→		shortID = shortID[:8]
   186→	}
   187→
   188→	pattern := filepath.Join(sessionDir, "session-*-"+shortID+".json")
   189→	matches, err := filepath.Glob(pattern)
   190→	if err == nil && len(matches) > 0 {
   191→		// Return the most recent match (last alphabetically, since date is in the name)
   192→		return matches[len(matches)-1]
   193→	}
   194→
   195→	// Fallback: construct a default path
   196→	return filepath.Join(sessionDir, agentSessionID+".json")
   197→}
