   318→// ExtractModifiedFilesFromOffset extracts files modified since a given message index.
   319→// For Gemini (JSON format), offset is the starting message index.
   320→// Returns:
   321→//   - files: list of file paths modified by Gemini (from Write/Edit tools)
   322→//   - currentPosition: total number of messages in the transcript
   323→//   - error: any error encountered during reading
   324→func (g *GeminiCLIAgent) ExtractModifiedFilesFromOffset(path string, startOffset int) (files []string, currentPosition int, err error) {
   325→	if path == "" {
   326→		return nil, 0, nil
   327→	}
   328→
   329→	data, readErr := os.ReadFile(path) //nolint:gosec // Reading from controlled transcript path
   330→	if readErr != nil {
   331→		if os.IsNotExist(readErr) {
   332→			return nil, 0, nil
   333→		}
   334→		return nil, 0, fmt.Errorf("failed to read transcript: %w", readErr)
   335→	}
   336→
   337→	if len(data) == 0 {
   338→		return nil, 0, nil
   339→	}
   340→
   341→	transcript, parseErr := ParseTranscript(data)
   342→	if parseErr != nil {
   343→		return nil, 0, parseErr
   344→	}
   345→
   346→	totalMessages := len(transcript.Messages)
   347→
   348→	// Extract files from messages starting at startOffset
   349→	fileSet := make(map[string]bool)
   350→	for i := startOffset; i < len(transcript.Messages); i++ {
   351→		msg := transcript.Messages[i]
   352→		// Only process gemini messages (assistant messages)
   353→		if msg.Type != MessageTypeGemini {
   354→			continue
   355→		}
   356→
   357→		// Process tool calls in this message
   358→		for _, toolCall := range msg.ToolCalls {
   359→			// Check if it's a file modification tool
   360→			isModifyTool := false
   361→			for _, name := range FileModificationTools {
   362→				if toolCall.Name == name {
   363→					isModifyTool = true
   364→					break
   365→				}
   366→			}
   367→
   368→			if !isModifyTool {
   369→				continue
   370→			}
   371→
   372→			// Extract file path from args map
   373→			var file string
   374→			if fp, ok := toolCall.Args["file_path"].(string); ok && fp != "" {
   375→				file = fp
   376→			} else if p, ok := toolCall.Args["path"].(string); ok && p != "" {
   377→				file = p
   378→			} else if fn, ok := toolCall.Args["filename"].(string); ok && fn != "" {
   379→				file = fn
   380→			}
   381→
   382→			if file != "" && !fileSet[file] {
   383→				fileSet[file] = true
   384→				files = append(files, file)
   385→			}
   386→		}
   387→	}
   388→
   389→	return files, totalMessages, nil
   390→}
