   392→// TranscriptChunker interface implementation
   393→
   394→// ChunkTranscript splits a Gemini JSON transcript by distributing messages across chunks.
   395→// Gemini uses JSON format with a {"messages": [...]} structure, so chunking splits
   396→// the messages array while preserving the JSON structure in each chunk.
   397→func (g *GeminiCLIAgent) ChunkTranscript(content []byte, maxSize int) ([][]byte, error) {
   398→	var transcript GeminiTranscript
   399→	if err := json.Unmarshal(content, &transcript); err != nil {
   400→		// Fall back to JSONL chunking if not valid Gemini JSON
   401→		chunks, chunkErr := agent.ChunkJSONL(content, maxSize)
   402→		if chunkErr != nil {
   403→			return nil, fmt.Errorf("failed to chunk as JSONL: %w", chunkErr)
   404→		}
   405→		return chunks, nil
   406→	}
   407→
   408→	if len(transcript.Messages) == 0 {
   409→		return [][]byte{content}, nil
   410→	}
   411→
   412→	var chunks [][]byte
   413→	var currentMessages []GeminiMessage
   414→	currentSize := len(`{"messages":[]}`) // Base JSON structure size
   415→
   416→	for i, msg := range transcript.Messages {
   417→		// Marshal message to get its size
   418→		msgBytes, err := json.Marshal(msg)
   419→		if err != nil {
   420→			logging.Warn(context.Background(), "failed to marshal Gemini message during chunking",
   421→				slog.Int("message_index", i),
   422→				slog.String("error", err.Error()),
   423→			)
   424→			continue
   425→		}
   426→		msgSize := len(msgBytes) + 1 // +1 for comma separator
   427→
   428→		if currentSize+msgSize > maxSize && len(currentMessages) > 0 {
   429→			// Save current chunk
   430→			chunkData, err := json.Marshal(GeminiTranscript{Messages: currentMessages})
   431→			if err != nil {
   432→				return nil, fmt.Errorf("failed to marshal chunk: %w", err)
   433→			}
   434→			chunks = append(chunks, chunkData)
   435→
   436→			// Start new chunk
   437→			currentMessages = nil
   438→			currentSize = len(`{"messages":[]}`)
   439→		}
   440→
   441→		currentMessages = append(currentMessages, msg)
   442→		currentSize += msgSize
   443→	}
   444→
   445→	// Add the last chunk
   446→	if len(currentMessages) > 0 {
   447→		chunkData, err := json.Marshal(GeminiTranscript{Messages: currentMessages})
   448→		if err != nil {
   449→			return nil, fmt.Errorf("failed to marshal final chunk: %w", err)
   450→		}
   451→		chunks = append(chunks, chunkData)
   452→	}
   453→
   454→	// Ensure we created at least one chunk (could be empty if all messages failed to marshal)
   455→	if len(chunks) == 0 {
   456→		return nil, errors.New("failed to create any chunks: all messages failed to marshal")
   457→	}
   458→
   459→	return chunks, nil
   460→}
   461→
   462→// ReassembleTranscript merges Gemini JSON chunks by combining their message arrays.
   463→func (g *GeminiCLIAgent) ReassembleTranscript(chunks [][]byte) ([]byte, error) {
   464→	var allMessages []GeminiMessage
   465→
   466→	for _, chunk := range chunks {
   467→		var transcript GeminiTranscript
   468→		if err := json.Unmarshal(chunk, &transcript); err != nil {
   469→			return nil, fmt.Errorf("failed to unmarshal chunk: %w", err)
   470→		}
   471→		allMessages = append(allMessages, transcript.Messages...)
   472→	}
   473→
   474→	result, err := json.Marshal(GeminiTranscript{Messages: allMessages})
   475→	if err != nil {
   476→		return nil, fmt.Errorf("failed to marshal reassembled transcript: %w", err)
   477→	}
   478→	return result, nil
   479→}
