   756→// ResolveAgentForRewind resolves the agent from checkpoint metadata.
   757→// Falls back to the default agent (Claude) for old checkpoints that lack agent info.
   758→func ResolveAgentForRewind(agentType agent.AgentType) (agent.Agent, error) {
   759→	if !isSpecificAgentType(agentType) {
   760→		ag := agent.Default()
   761→		if ag == nil {
   762→			return nil, errors.New("no default agent registered")
   763→		}
   764→		return ag, nil
   765→	}
   766→	ag, err := agent.GetByAgentType(agentType)
   767→	if err != nil {
   768→		return nil, fmt.Errorf("resolving agent %q: %w", agentType, err)
   769→	}
   770→	return ag, nil
