   773→// ResolveSessionFilePath determines the correct file path for an agent's session transcript.
   774→// Checks session state for transcript_path first (needed for agents like Gemini that store
   775→// transcripts at paths that GetSessionDir can't reconstruct, e.g. SHA-256 hashed directories).
   776→// Falls back to the agent's ExtractAgentSessionID + ResolveSessionFile with fallbackSessionDir.
   777→func ResolveSessionFilePath(sessionID string, ag agent.Agent, fallbackSessionDir string) string {
   778→	state, err := LoadSessionState(sessionID)
   779→	if err == nil && state != nil && state.TranscriptPath != "" {
   780→		return state.TranscriptPath
   781→	}
   782→
   783→	agentSessionID := ag.ExtractAgentSessionID(sessionID)
   784→	return ag.ResolveSessionFile(fallbackSessionDir, agentSessionID)
   785→}
