   795→
   796→	tree, err := commit.Tree()
   797→	if err != nil {
   798→		return ""
   799→	}
   800→
   801→	// Look for prompt.txt in the metadata directory
   802→	promptPath := metadataDir + "/" + paths.PromptFileName
