   816→// SessionRestoreStatus represents the status of a session being restored.
   817→type SessionRestoreStatus int
   818→
   819→const (
   820→	StatusNew             SessionRestoreStatus = iota // Local file doesn't exist
   821→	StatusUnchanged                                   // Local and checkpoint are the same
   822→	StatusCheckpointNewer                             // Checkpoint has newer entries
   823→	StatusLocalNewer                                  // Local has newer entries (conflict)
   824→)
