   826→// SessionRestoreInfo contains information about a session being restored.
   827→type SessionRestoreInfo struct {
   828→	SessionID      string
   829→	Prompt         string               // First prompt preview for display
   830→	Status         SessionRestoreStatus // Status of this session
   831→	LocalTime      time.Time
   832→	CheckpointTime time.Time
