   835→// classifySessionsForRestore checks all sessions in a checkpoint and returns info
   836→// about each session, including whether local logs have newer timestamps.
   837→// repoRoot is used to compute per-session agent directories.
   838→// Sessions without agent metadata are skipped (cannot determine target directory).
   839→func (s *ManualCommitStrategy) classifySessionsForRestore(ctx context.Context, repoRoot string, store cpkg.Store, checkpointID id.CheckpointID, summary *cpkg.CheckpointSummary) []SessionRestoreInfo {
   840→	var sessions []SessionRestoreInfo
   841→
   842→	totalSessions := len(summary.Sessions)
   843→	// Check all sessions (0-based indexing)
   844→	for i := range totalSessions {
   845→		content, err := store.ReadSessionContent(ctx, checkpointID, i)
   846→		if err != nil || content == nil || len(content.Transcript) == 0 {
   847→			continue
   848→		}
   849→
   850→		sessionID := content.Metadata.SessionID
   851→		if sessionID == "" || content.Metadata.Agent == "" {
   852→			continue
   853→		}
   854→
   855→		sessionAgent, agErr := ResolveAgentForRewind(content.Metadata.Agent)
   856→		if agErr != nil {
   857→			continue
   858→		}
   859→
   860→		sessionAgentDir, dirErr := sessionAgent.GetSessionDir(repoRoot)
   861→		if dirErr != nil {
   862→			continue
   863→		}
   864→
   865→		localPath := ResolveSessionFilePath(sessionID, sessionAgent, sessionAgentDir)
   866→
   867→		localTime := paths.GetLastTimestampFromFile(localPath)
   868→		checkpointTime := paths.GetLastTimestampFromBytes(content.Transcript)
   869→		status := ClassifyTimestamps(localTime, checkpointTime)
   870→
   871→		sessions = append(sessions, SessionRestoreInfo{
   872→			SessionID:      sessionID,
   873→			Prompt:         ExtractFirstPrompt(content.Prompts),
   874→			Status:         status,
   875→			LocalTime:      localTime,
   876→			CheckpointTime: checkpointTime,
   877→		})
   878→	}
   879→
   880→	return sessions
   881→}
   882→
   883→// ClassifyTimestamps determines the restore status based on local and checkpoint timestamps.
   884→func ClassifyTimestamps(localTime, checkpointTime time.Time) SessionRestoreStatus {
   885→	// Local file doesn't exist (no timestamp found)
   886→	if localTime.IsZero() {
   887→		return StatusNew
   888→	}
   889→
   890→	// Can't determine checkpoint time - treat as new/safe
   891→	if checkpointTime.IsZero() {
   892→		return StatusNew
   893→	}
   894→
   895→	// Compare timestamps
   896→	if localTime.After(checkpointTime) {
   897→		return StatusLocalNewer
   898→	}
   899→	if checkpointTime.After(localTime) {
   900→		return StatusCheckpointNewer
   901→	}
   902→	return StatusUnchanged
   903→}
