   905→// StatusToText returns a human-readable status string.
   906→func StatusToText(status SessionRestoreStatus) string {
   907→	switch status {
   908→	case StatusNew:
   909→		return "(new)"
   910→	case StatusUnchanged:
   911→		return "(unchanged)"
   912→	case StatusCheckpointNewer:
   913→		return "(checkpoint is newer)"
   914→	case StatusLocalNewer:
   915→		return "(local is newer)" // shouldn't appear in non-conflict list
   916→	default:
   917→		return ""
   918→	}
   919→}
   920→
   921→// PromptOverwriteNewerLogs asks the user for confirmation to overwrite local
   922→// session logs that have newer timestamps than the checkpoint versions.
   923→func PromptOverwriteNewerLogs(sessions []SessionRestoreInfo) (bool, error) {
   924→	// Separate conflicting and non-conflicting sessions
   925→	var conflicting, nonConflicting []SessionRestoreInfo
   926→	for _, s := range sessions {
   927→		if s.Status == StatusLocalNewer {
   928→			conflicting = append(conflicting, s)
   929→		} else {
   930→			nonConflicting = append(nonConflicting, s)
   931→		}
   932→	}
   933→
   934→	fmt.Fprintf(os.Stderr, "\nWarning: Local session log(s) have newer entries than the checkpoint:\n")
   935→	for _, info := range conflicting {
   936→		// Show prompt if available, otherwise fall back to session ID
   937→		if info.Prompt != "" {
   938→			fmt.Fprintf(os.Stderr, "  \"%s\"\n", info.Prompt)
   939→		} else {
   940→			fmt.Fprintf(os.Stderr, "  Session: %s\n", info.SessionID)
   941→		}
   942→		fmt.Fprintf(os.Stderr, "    Local last entry:      %s\n", info.LocalTime.Local().Format("2006-01-02 15:04:05"))
   943→		fmt.Fprintf(os.Stderr, "    Checkpoint last entry: %s\n", info.CheckpointTime.Local().Format("2006-01-02 15:04:05"))
   944→	}
   945→
   946→	// Show non-conflicting sessions with their status
   947→	if len(nonConflicting) > 0 {
   948→		fmt.Fprintf(os.Stderr, "\nThese other session(s) will also be restored:\n")
   949→		for _, info := range nonConflicting {
   950→			statusText := StatusToText(info.Status)
   951→			if info.Prompt != "" {
   952→				fmt.Fprintf(os.Stderr, "  \"%s\" %s\n", info.Prompt, statusText)
   953→			} else {
   954→				fmt.Fprintf(os.Stderr, "  Session: %s %s\n", info.SessionID, statusText)
   955→			}
   956→		}
   957→	}
   958→
   959→	fmt.Fprintf(os.Stderr, "\nOverwriting will lose the newer local entries.\n\n")
   960→
   961→	var confirmed bool
   962→	form := huh.NewForm(
   963→		huh.NewGroup(
   964→			huh.NewConfirm().
   965→				Title("Overwrite local session logs with checkpoint versions?").
   966→				Value(&confirmed),
   967→		),
   968→	)
   969→	if isAccessibleMode() {
   970→		form = form.WithAccessible(true)
   971→	}
   972→
   973→	if err := form.Run(); err != nil {
   974→		if errors.Is(err, huh.ErrUserAborted) {
   975→			return false, nil
   976→		}
   977→		return false, fmt.Errorf("failed to get confirmation: %w", err)
   978→	}
   979→
   980→	return confirmed, nil
   981→}
